Query.SQL:
SELECT DECODE(COUNT(*),0,'false','true') AS "CP.IS_CODED_PARTY" 
FROM   CODED_PARTIES CP
WHERE  CP.PARTY_ID = ${param.partyId}

SELECT DECODE(COUNT(*),0,'false','true') AS "CPR.IS_CASE_PARTY_ROLES" 
FROM   CASE_PARTY_ROLES CPR
WHERE  CPR.CASE_NUMBER = ${param.caseNumber}
AND    CPR.PARTY_ID    = ${param.partyId}
